def trimmed_mean(nums):
    if not nums:
        return None
    else:
        nums.sort()
        if len(nums) <= 1:
            return float('NaN')
        min_, max_ = nums[0], nums[-1]
        del nums[nums.index(min_) for _ in range(2)]
        del nums[nums.index(max_) for _ in range(2)]
        return sum(nums) / (len(nums) - 2)
